      "mainEntity": [
        {
          "@type": "Question",
          "name": "When does the 45-day clock under Section 43B(h) start?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "The clock starts on the day the goods are accepted or the service is rendered, or on the day objections raised within 15 days are removed. Where a written agreement exists the limit is the agreed credit period capped at 45 days; with no written agreement it is 15 days. A bill accepted on 1 March is due by 15 April."
          }
        },
        {
          "@type": "Question",
          "name": "Does Section 43B(h) apply to medium enterprises as well?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "No. Section 43B(h) covers only micro and small enterprises registered on the Udyam portal, and medium enterprises fall outside it entirely. Traders registered as micro or small are also outside, because the payment protection in Section 15 of the MSMED Act extends to manufacturers and service providers. Checking the supplier's Udyam certificate category is the practical first step."
          }
        },
        {
          "@type": "Question",
          "name": "What happens if a micro or small supplier is paid after the Section 43B(h) deadline?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "The expense is disallowed in the year it was booked and becomes deductible only in the year the payment is actually made, so tax falls due on profit that never existed in cash. Rs 40 lakh of unpaid micro and small vendor bills outstanding at 31 March adds Rs 40 lakh to taxable income for that year."
          }
        }
